function Controller(prefix: string) {
  return function (constructor: Function) {
    constructor.prototype.prefix = prefix;
  };
}

@Controller('/api/users')
class UserController {
  getUsers() {
    return ["Alice", "Bob"];
  }
}

const userController = new UserController();
console.log(userController.prefix);  // Output: /api/users

function Get(path: string) {
  return function (target: any, propertyKey: string, descriptor: PropertyDescriptor) {
    if (!target.routes) {
      target.routes = [];
    }
    target.routes.push({ method: 'GET', path, handlerName: propertyKey });
  };
}

class UserController {
  @Get('/')
  getUsers() {
    return ["Alice", "Bob"];
  }

  @Get('/:id')
  getUserById() {
    return { id: 1, name: "Alice" };
  }
}

const controller = new UserController();
console.log(controller.routes);
// Output: [
//   { method: 'GET', path: '/', handlerName: 'getUsers' },
//   { method: 'GET', path: '/:id', handlerName: 'getUserById' }
// ]

function Required(target: any, propertyKey: string) {
  if (!target.requiredProps) {
    target.requiredProps = [];
  }
  target.requiredProps.push(propertyKey);
}

class User {
  @Required
  name!: string;

  age?: number;
}

const user = new User();
console.log(user.requiredProps);  // Output: ['name']

import 'reflect-metadata';

function LogType(target: any, propertyKey: string) {
  const type = Reflect.getMetadata("design:type", target, propertyKey);
  console.log(`${propertyKey} type: ${type.name}`);
}

class Demo {
  @LogType
  myNumber!: number;

  @LogType
  myString!: string;
}

const demo = new Demo();
// Console Output:
// myNumber type: Number
// myString type: String

class CustomError extends Error {
  constructor(message: string) {
    super(message); 
    this.name = 'CustomError';
    Object.setPrototypeOf(this, CustomError.prototype); 
  }
}

// Usage example
try {
  throw new CustomError('Something went wrong!');
} catch (error) {
  if (error instanceof CustomError) {
    console.log('Caught a custom error:', error.message);
  } else {
    console.log('Caught an unknown error');
  }
}

class ValidationError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'ValidationError';
    Object.setPrototypeOf(this, ValidationError.prototype);
  }
}

class DatabaseError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'DatabaseError';
    Object.setPrototypeOf(this, DatabaseError.prototype);
  }
}

function processUserInput(input: string) {
  if (!input) {
    throw new ValidationError('Input cannot be empty');
  }
  // process input...
}

try {
  processUserInput('');
} catch (error) {
  if (error instanceof ValidationError) {
    console.error('Validation error occurred:', error.message);
  } else if (error instanceof DatabaseError) {
    console.error('Database error:', error.message);
  } else {
    console.error('Unknown error:', error);
  }
}

def safe_divide(x):
    if x == 0:
        raise ValueError("Division by zero")
    return 10 / x

numbers = [5, 2, 0, 4]

# Using map (lazy evaluation) with try-except inside the loop to handle errors gracefully
results = map(safe_divide, numbers)

for result in results:
    try:
        print(result)
    except ValueError as e:
        print(f"Error: {e}")
